&lt;p class=&quot;MsoNormal&quot; style=&quot;text-align:left;line-height:200%;text-indent:24pt;mso-pagination:widow-orphan;&quot;&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;牛牛的大小：大王牛&amp;nbsp;&amp;gt;&amp;nbsp;小王牛&amp;nbsp;&amp;gt;&amp;nbsp;K牛&lt;/span&gt;&lt;/p&gt;
