&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;mso-bidi-font-family:arial;&quot;=&quot;&quot;&gt;庄位：做庄的玩家的位置，不能押注的位置；&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:9pt;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;mso-bidi-font-family:arial;&quot;=&quot;&quot;&gt;闲家：即不做庄的玩家，每局闲家人数不限；&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:9pt;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;mso-bidi-font-family:arial;&quot;=&quot;&quot;&gt;闲位：即闲家下注的位置，有&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;4&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;mso-bidi-font-family:arial;&quot;=&quot;&quot;&gt;个闲位，分别为天、地、玄、黄；&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:9pt;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-font-kerning:0.0000pt;mso-bidi-font-family:arial;&quot;=&quot;&quot;&gt;下注：即押注，只能由闲家进行下注，也只能下注到任意一个闲位上。&lt;/span&gt;&lt;/p&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A5AF012E80C8 AS DateTime), CAST(0x0000A63200CF3AB9 AS DateTime), 3451, 7)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (108, N'碰碰车', N'/Upload/Rules/38.png', N'/Upload/Rules/39.png', 0, N'', N'', N'&lt;span style=&quot;font-size:16px;&quot;&gt;百人碰碰车，是网络比较流行的&lt;/span&gt;&lt;a href=&quot;http://baike.baidu.com/view/17935.htm&quot; target=&quot;_blank&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;休闲游戏&lt;/span&gt;&lt;/a&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;，色彩绚丽，玩法新颖。游戏中有4个汽车标志大小两种方式代表八个不同的下注区域，游戏玩家可以在游戏过程中任意选择自己喜欢的区域投放筹码。&lt;/span&gt;', N'&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 2.4pt;text-align:left;line-height:14.4pt;text-indent:24pt;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;坐庄规则&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:2.4pt 0cm 0pt;text-align:left;line-height:14.4pt;text-indent:24pt;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;本游戏基础坐庄为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;20&lt;/span&gt;把，每把身上的银子必须符合申请房间的上庄条件。&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;20&lt;/span&gt;把之后需每把符合翻&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;10&lt;/span&gt;倍的条件才可继续坐庄，最多坐庄&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;40&lt;/span&gt;把，然后轮换庄家。在符合上庄条件后，如果庄家身上的钱不够下一次坐庄，在结算动画的&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;秒内是庄家取钱时间，庄家没取钱，钱不够下次坐庄则轮换庄家，由庄家列表内按顺序排在最上面的庄家来坐庄。庄家在，坐庄&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;20&lt;/span&gt;把以后需每把符合翻&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;10&lt;/span&gt;倍的条件才可继续坐庄，如果钱不够则轮换庄家。由上庄列表中最上面排列的庄家坐庄重新计算庄家坐庄的次数。只要轮换庄家，坐庄次数就会被刷新。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 2.4pt;text-align:left;line-height:14.4pt;text-indent:24pt;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;压注规则&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;庄家上庄 庄家的银子数&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;+&lt;/span&gt;闲家的所压的银子大于或等于玩家压注银子所陪的倍数&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;例如：设有闲家&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; x1&lt;/span&gt;，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; x2&lt;/span&gt;，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; x3 &lt;/span&gt;所有的倍数为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; b1&lt;/span&gt;，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; b2&lt;/span&gt;，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; b3 &lt;/span&gt;庄家钱数为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;Z&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;已知&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; x1 x2 &lt;/span&gt;的押注数 求&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;x3&lt;/span&gt;的最大可压注数（也就是闲家之间的联系）&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;Z+&lt;/span&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;（&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;x1+x2&lt;/span&gt;）&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;&amp;gt;=x3*b3&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;根据玩家的压注数 区域最大压注数也会跟着变化。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;下分规则&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin-top:2.4pt;margin-right:0cm;&amp;#10;margin-bottom:2.4pt;margin-left:0cm;text-align:left;text-indent:24.0pt;&amp;#10;line-height:14.4pt;mso-pagination:widow-orphan;background:white;&quot;&gt;&lt;span style=&quot;color:#454545;font-family:宋体;font-size:16px;&quot;&gt;大奔驰、小奔驰、大宝马、小宝马、大奥迪、小奥迪、大大众、小大众等&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;个区域，下注赔率之间是相互叠加的。&lt;/span&gt;&lt;/p&gt;
