&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 0pt;text-align:left;line-height:16.5pt;&quot;&gt;&lt;b&gt;&lt;span style=&quot;color:black;font-family:宋体;font-size:16px;&quot;&gt;游戏大小顺序：&lt;/span&gt;&lt;/b&gt;&lt;span style=&quot;color:black;font-family:宋体;font-size:16px;&quot;&gt;白板＞&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;筒＞&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;筒＞&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;7&lt;/span&gt;筒＞&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;6&lt;/span&gt;筒＞。。。。。。。&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;1&lt;/span&gt;筒。&lt;/span&gt;&lt;/p&gt;
