&lt;/table&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 0pt;text-align:left;line-height:16.5pt;&quot;&gt;&lt;span style=&quot;color:black;font-family:宋体;font-size:16px;&quot;&gt;解释：玩家有&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;3&lt;/span&gt;个正门&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;2&lt;/span&gt;个角和一个横押注。正门只要输了就没了，要赢了也就有了已经押的分数。角和横是代表&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;2&lt;/span&gt;门一起的赌注，一门有一门无，那就代表玩家不输赢。两门都有玩家就赢了押的底注，反之就输了押的底注。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 0pt;text-align:left;line-height:16.5pt;&quot;&gt;&lt;b&gt;&lt;span style=&quot;color:black;font-family:宋体;font-size:16px;&quot;&gt;逃跑惩罚：&lt;/span&gt;&lt;/b&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;background:white;margin:0cm 0cm 0pt;text-align:left;line-height:16.5pt;text-indent:10pt;&quot;&gt;&lt;span style=&quot;color:black;font-family:宋体;font-size:16px;&quot;&gt;逃跑玩家按照正常的输的分扣除，游戏继续中，庄家逃跑扣除闲家所押的注数，游戏结束。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;br /&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A63200CFEBD9 AS DateTime), CAST(0x0000A63200D06572 AS DateTime), 6412, 8)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (123, N'飞禽走兽', N'/Upload/Rules/42.png', N'/Upload/Rules/43.png', 0, N'', N'', N'&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;飞禽走兽网络游戏是一款极具娱乐性和刺激性的大型轮盘类游戏，玩家&lt;/span&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;通过游戏界面选择要压的动物，分三大类，飞禽类，走兽类，大白鲨，中了其中一个，就可以得到压中的分数乘以相对的倍数的积，然后进入第二次压分&lt;/span&gt;&lt;/p&gt;', N'&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1．玩家进入游戏之后，可以开始选择下注金币的额度。&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2．当玩家获得彩金时，可获得一定数量的彩金奖。&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3．每种动物分别对应着飞禽和走兽俩种动物类型。玩家可以在飞禽和走兽上面押分，如果压中，则获得对应的游戏倍数积。&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4．游戏除了提供玩家8种动物的押分之外，还提供了金鲨银鲨的押分。玩家可以通过对齐押分，获得更高倍数的收益哦。&lt;/span&gt;&lt;/p&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A6180146F65C AS DateTime), CAST(0x0000A63200D032E1 AS DateTime), 5621, 9)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (126, N'将相和', N'/Upload/Rules/51.png', N'/Upload/Rules/52.jpg', 0, N'', N'', N'&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;将相和源于意大利，简单的推理和快速运算是将相和最大特点，因而从十九世纪即为广受欢迎的扑克游戏。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;br /&gt;', N'&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;游戏使用&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;副扑克牌：&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&#183;
&amp;nbsp; &lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;荷官会派出&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;“&lt;/span&gt;将&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;和&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;“&lt;/span&gt;相&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;两份牌。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&#183;
&amp;nbsp; A&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;是&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;1&lt;/span&gt;点，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;2&lt;/span&gt;到&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;的牌面即为点数，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;K&lt;/span&gt;、&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;Q&lt;/span&gt;、&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;J&lt;/span&gt;、&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;10&lt;/span&gt;是&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;0&lt;/span&gt;点，加起来等于&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;10&lt;/span&gt;也当作是&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;0&lt;/span&gt;点；总数&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;点或最接近&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;点的一家胜出。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&#183;
&amp;nbsp; &lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;当任何一家起手牌的点数总和为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;或&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;，就称为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;“&lt;/span&gt;天王&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;，牌局就算结束，双方不再补牌。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&#183;
&amp;nbsp; &lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;你有&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;5&lt;/span&gt;种下注选择：&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;◎&lt;/span&gt;相&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; ◎&lt;/span&gt;将&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; ◎&lt;/span&gt;和局&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; ◎&lt;/span&gt;将天王&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt; ◎&lt;/span&gt;相天王。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&#183;
&amp;nbsp; &lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;派完起手牌，将依补牌规则补&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;1&lt;/span&gt;张牌。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;和局时，&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;“&lt;/span&gt;将／相&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;的下注将退回。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;将天王&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;指将的起手牌为起手点数为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;或&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;点（天王牌）。&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;相天王&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;”&lt;/span&gt;指相的起手牌为起手点数为&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;8&lt;/span&gt;或&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;9&lt;/span&gt;点（天王牌）。&lt;/span&gt;&lt;/p&gt;
