&lt;tr style=&quot;mso-yfti-irow:5;mso-yfti-lastrow:yes;height:18.65pt;&quot;&gt;&lt;td width=&quot;20%&quot; valign=&quot;top&quot; style=&quot;background:#eaeaea;border-width:0px 1pt 1pt;border-style:none solid solid;border-color:#000000 windowtext windowtext;padding:1.5pt 3.75pt;border-image:none;width:20.6%;height:18.65pt;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;   &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;相天王&lt;/span&gt;&lt;/p&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;   &lt;/span&gt;&lt;/td&gt;
&lt;td width=&quot;79%&quot; valign=&quot;top&quot; style=&quot;background:#eaeaea;border-width:0px 1pt 1pt 0px;border-style:none solid solid none;border-color:#000000 windowtext windowtext #000000;padding:1.5pt 3.75pt;width:79.4%;height:18.65pt;&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;   &lt;/span&gt;&lt;p align=&quot;left&quot; style=&quot;margin:0cm 0cm 6pt;text-align:left;&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;1&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;赔&lt;span lang=&quot;EN-US&quot; style=&quot;font-size:16px;&quot;&gt;3&lt;/span&gt;&lt;/span&gt;&lt;/p&gt;
