&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;/div&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A63200D699D7 AS DateTime), CAST(0x0000A63200D699D7 AS DateTime), 5642, 9)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (200, N'斗地主', N'/Upload/Rules/27.png', N'/Upload/Rules/28.jpg', 0, N'', N'', N'&lt;span style=&quot;font-size:14px;&quot;&gt;斗地主是流行于湖北一带的一种扑克游戏，玩法简单，娱乐性强，老少皆宜。据传在万恶的旧社会，地主横行乡里，无恶不做，人们为了发泄对地主的痛恨，常常在一天的劳作之后，一家人关起门来&quot;斗地主&quot;。 &lt;/span&gt;&lt;br /&gt;', N'&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;发牌&lt;/span&gt;：三人斗地主一副牌54张，每人17张，3张留作底牌。地主确定之前底牌不可见。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;抢地主&lt;/span&gt;：系统自动选择一玩家叫地主，此家不叫，轮流到下家，直到一家叫地主。一家叫地主后，未有轮到叫地主的玩家可选择抢地主。抢地主过后，叫地主的玩家有一次再抢地主机会。如有再抢，此玩家做地主；如没再抢，最后一位抢地主的玩家做地主。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;地主会获得三张底牌，三张底牌在地主确认之后自动明牌，玩家都可见。地主共有20张牌。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;出牌&lt;/span&gt;：地主第一家出牌，之后按照逆时针方向各位玩家依次出牌。下家有大过上家出的同牌型点数时方能出牌，没规定有牌必出，玩家可选择“出牌”和“不出”。点数大小比较中不计花色。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;炸弹&lt;/span&gt;：玩家出炸弹或者火箭，本局总倍数*2&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;春天及反春&lt;/span&gt;：地主出完所有牌，两农民都一张未出，即为春天，本局总倍数*2；地主出第一张牌后，一家农民连续出完所有牌，即为反春，本局总倍数*2。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;结算&lt;/span&gt;：&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;农民赢：农民中一家先出完牌，结算公式为：各房间底分*全局加倍倍数*农民加倍倍数（不加倍为1）。地主输两家农民各赢乐豆之和。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;地主赢：地主先出完牌，地主赢农民两家乐豆之和。农民输各自结算乐豆数量。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;逃跑处理&lt;/span&gt;：&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;逃跑规定：在玩家坐下并都已准备后，玩家离开本房间即视为逃跑行为。在逃跑行为中，凡是本局有炸弹的，无论是否已经炸出，都按照炸弹加倍来结算逃跑罚率。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;地主逃跑：如果逃跑时本局总倍数不足10倍，按照20倍处罚。如果超过10倍则按照实际倍数的4倍处罚。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;农民逃跑：如果逃跑时本局总倍数不足10倍，每人按照10倍处罚。 如果超过 10倍按照实际倍数的 2倍处罚。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#e53333;font-size:16px;&quot;&gt;牌型及大小&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;火箭&lt;/span&gt;：大王+小王，是最大的炸弹，也是三人斗地主中最大的牌。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;炸弹&lt;/span&gt;：四张点数一致的牌，如7777&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;单牌&lt;/span&gt;：单个牌，如7&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;对牌&lt;/span&gt;：点数相同的牌，如77&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;三张牌&lt;/span&gt;：点数相同的三张牌，如777&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;三带一&lt;/span&gt;：三张带一单或者一对，如777+3或者777+33&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;单顺&lt;/span&gt;：五张及以上点数相连的单牌，不包括2和双王，如34567或910JQKA。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;双顺&lt;/span&gt;：三对及以上点数相连对牌，不包括2和双王，如334455或JJQQKKAA。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;三顺&lt;/span&gt;：两个及以上连续点数的三张牌，不包括2和双王，如333444,555666777888&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;飞机带翅膀&lt;/span&gt;：三顺+同数量的单牌或同数量的对牌，如333444+5+6或者555666777+33+44+88&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;color:#006600;&quot;&gt;四带二&lt;/span&gt;：四张同点数的牌+两张单牌或者两对对牌，如3333+4+5或3333+44+77&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;（以上牌型都不计花色，复合牌型中，大小王不能作为带牌的单牌，对子不能作为带牌的单牌出现，如333444+8+8。）&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;火箭&amp;gt;炸弹&amp;gt;其他牌型。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;同为炸弹，比较炸弹点数大小。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;同为复合牌型——三带、四带，比较三张、四张牌的点数大小。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;同为顺子牌型——单顺、双顺、三顺、飞机带翅膀，比较顺牌中最大点数牌大小。&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;同为单独牌型——单张、对子、三张，比较各自牌型点数大小。&lt;br /&gt;
&lt;br /&gt;
&lt;/div&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A5B10125ECEF AS DateTime), CAST(0x0000A5B10125ECEF AS DateTime), 5231, 8)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (301, N'血战麻将', N'/Upload/Rules/49.png', N'/Upload/Rules/50.jpg', 0, N'', N'', N'&lt;span style=&quot;font-size:16px;&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;血战麻将采用四川地区流行的麻将打法，尤其是成都及周边比较盛行的打法。核心是打缺门（定张后勇往直前），刮风下雨，成都计番，流局查卫生（查花猪）。同时，我们以提供血战模式，让大家打得激烈尽兴；一局牌中，一家胡牌并不结束牌局，而是未胡的玩家继续打，直到3家胡牌或剩余的玩家流局。这样先胡的玩家并不一定获利最多。点炮的玩家也能翻身，提高了趣味性，促进了牌局的稳定发展。牌局结束，一并结算。&lt;/span&gt;&lt;br /&gt;', N'&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1. 庄家：由东风位方向选择庄家。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2. 出牌：庄家14张牌开打，每次打一张，其他三家按照逆时针顺序开打，每次打之前如果不出现碰，杠，抢杠，胡，则系统会自动摸牌，摸牌后如果不完成杠牌动作，则也必须打出自己手中的一张牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3. 胡牌：主要使自己手中的牌或者碰，杠的牌最终形成牌形为：三，三，三，三，二的形状或为七对子。（注明：三如果为杠子，则可以出现四个牌）&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4. 顺子：万子，条子，筒子三种牌形中，由相邻数子的三张牌组成。例如：一万两万三万，组成一个顺子。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5. 坎子：任意牌形（除了花以外），由相同的三张牌组成。例如：三个一万，三个九筒等等。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;6. 杠子：任意牌形（除了花以外），由相同的四张牌组成。例如：四个一万，四个八条等等。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;7. 碰：当其他三位玩家所打出牌与自己手中的两张牌对应，组合成刻子，可以选择碰牌。碰完牌后手中两张牌和那一张牌相对应，摆自己面前。然后将自己手中的牌打出一张。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;8. 杠：杠的方式有三种。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;a) 直杠：当其他用户打出的牌，自己手中有三张与之对应，组合成杠子，可以选择杠牌。杠完牌后，可以继续摸一张牌（麻将摸牌顺序中的最后一张），如果没能自摸，则再选择自己手中的牌打出一张。这种杠的方式为明杠。（刮风）&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;b) 面下杠：当自己已经碰过其他玩家，而自己又摸到了那张牌，则可以选择杠牌。杠完后，可以继续摸一张牌（麻将摸牌顺序中的最后一张），如果没能自摸，则再选择自己手中的牌打出一张。这种杠的方式为明杠。（刮风）&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;c) 暗杠：当自己手中有三张一样的牌，已经组成刻子，如果再摸到一张相同的牌，可以选择杠牌。杠完后，可以继续摸一张牌（麻将摸牌顺序中的最后一张），如果没能自摸，则再选择自己手中的牌打出一张。这种杠的方式为暗杠。（下雨）&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;9. 胡：所胡牌为他人放出的牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;自摸：所胡牌为自己正常摸得，即称之为自摸胡，简称“自摸”。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;b&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;打牌规则&lt;/span&gt;&lt;/b&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;血战到底麻将（成都）使用去掉字牌、花牌，只留条、筒、万的108张牌。游戏人数为4人，每人手里抓13张牌，不能吃牌，可以碰牌或杠牌，手牌满足相关规定的牌型条件时胡牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;1.实行血战到底，明杠、暗杠均要得分。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;2.根据不同房间封顶番数不同，刮风、下雨另算，不包括在内。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;3.未换人前提下，除第一盘随机选择一人做庄之外，以后每盘由上一盘首先胡牌人做庄；一炮多响时，下盘由放炮人做庄。如1：D是庄，A首先胡了，BCD继续打，B同时放炮给C、D，下局庄家则为A玩家；如2：D是庄，A首先胡了，BCD继续打，B先后放炮给C和D，下局庄家为A玩家。换人后第一盘随机选庄。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;4.不能吃牌，只能碰、杠，杠牌从牌墙正常位置补牌。暗杠也必须亮一个牌出来。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;5.荒庄不下庄。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;6.必须缺一门才可以和牌，即胡牌的时候不能有三种花色的牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;7.游戏开始前，玩家需要选择一门要打缺的花色来，定缺后玩家必须在打完所持有的已定缺花色的牌之后，才可以打出其他花色的牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;8.4副顺子或坎（杠）加1对可以和牌；7副对子可以和牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;9.点炮时点炮者只负责自己的输分，允许一炮多响。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;10.胡牌时若为自摸或杠上花，则三家输分。分承包制和家家有房间&amp;lt;具体可参照QQ游戏四川麻将&amp;gt;,承包制:即引杠者本人负责杠上花分数,与其他未胡牌玩家无关;家家有:若为杠某家打出的牌而杠上开花，则所有未胡牌的玩家输分。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;11.杠后点炮时，点炮者将开杠所得转移给被点炮者，若杠后点炮超过一响，点炮者要另赔出开杠所得的点数给所有被点者。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;12.打牌时，在自己未摸下一张牌的一圈内，不能弃上一家而胡下一家。若加翻可胡牌。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;13.剩最后一圈牌（即4张），若有人点炮由玩家选择胡牌(即可以不胡牌)，自摸也必须胡牌。自摸可不胡牌&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;14点炮时点炮者只负责自己的输分（其他玩家不要输分）。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;15.和牌时若为自摸(不包括引杠)，则三家输点；若为点炮，则点炮者输点；若为杠某家打出的牌而杠上开花，则三家输点，引杠者需要多出引杠的分；允许一炮多响。&lt;/span&gt;&lt;/div&gt;
&lt;div&gt;&lt;br /&gt;
&lt;/div&gt;
&lt;div&gt;&lt;span style=&quot;font-size:16px;&quot;&gt;16.其中只剩最后四张牌的情况，不能在明叫了、有人点炮则自动和牌，自摸也必须和牌。没有明叫这一功能.最后四张自摸可不胡牌(查叫查大翻)。&lt;/span&gt;&lt;/div&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A63200D29FEB AS DateTime), CAST(0x0000A63200D29FEB AS DateTime), 7845, 7)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (400, N'中国象棋', N'/Upload/Rules/47.png', N'/Upload/Rules/48.jpg', 0, N'', N'', N'&lt;span style=&quot;font-size:16px;&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;中国象棋在中国有着悠久的历史，属于二人对抗性游戏的一种。由于用具简单，趣味性强，成为流行极为广泛的棋艺活动。是我国正式开展的78个体育项目之一，为促进该项目在世界范围内的普及和推广，在中国古代，象棋被列为士大夫们的修身之艺，现在则被视为怡神益智的一种有益的活动。在棋战中，人们可以从攻与防、虚与实、整体与局部等复杂关系的变化中悟出某种哲理。&lt;/span&gt;&lt;br /&gt;', N'&lt;span style=&quot;font-size:16px;&quot;&gt;开局&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;对局时，由执红棋的一方先走，双方轮流各走一着，直至分出胜、负、和，对局即终了。&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;走法&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;帅(将)每一着只许走一步，前进、后退、横走都可以，但不能离开“九宫”。将和帅不准在同一直线上直接对面，如一方已先占据，另一方必须回避，否则判负。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;士每一着只许沿“九宫”斜线走一步，可进可退。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;相(象)不能越过“河界”，每一着斜走两步，可进可退，即俗称“相(象)走田字”。当田字中心有别的棋子时，俗称“塞(相)象眼”，则不能走。马每着走一直(或一横)一斜，可进可退，即俗称“马走日字”。如果在要去的方向有别的棋子挡住。俗称“蹩马腿”，则不能走。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;车每一着可以直进、直退、横走，不限步数。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;炮在不吃子的时候，走法同车一样。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;兵(卒)在没有过“河界”前，每着只许向前直走一步；过“河界”后，每着可向前直走或横走一步，但不能后退。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;走一着棋时，如果己方棋子能够走到的位置有对方棋子存在，就可以把对方棋子吃掉而占领那个位置。只有炮吃子时必须隔一个棋子(无论是哪一方的)跳吃，即俗称“炮打隔子”。&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;三、杀棋和困毙&lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;杀棋一方的棋子攻击对方的帅(将)，并在下一着要把它吃掉，称为“照将”，或简称“将”。被“照将”的一方必须立即“应将”，即用自己的着法去化解被“将”的状态。如果被“照将”而无法“应将”，就算被“将死”。 &lt;/span&gt;&lt;br /&gt;
&lt;span style=&quot;font-size:16px;&quot;&gt;困毙轮到走棋的一方，无子可走，就算被“困毙”。&lt;/span&gt;&lt;br /&gt;
&lt;br /&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A63200D1BBBC AS DateTime), CAST(0x0000A63200D1BBBC AS DateTime), 3623, 7)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (401, N'五子棋', N'/Upload/Rules/45.png', N'/Upload/Rules/46.jpg', 0, N'', N'', N'&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;又名五子连珠棋，是一项有趣、益智的棋类游戏，世界上已有数十个国家开展此项活动。世界五子连珠棋锦标赛已举办过几届，并进入世界智力体育奥林匹克比赛，它的影响越来越大。五子连珠棋易学难精，但妙趣横生。下一局棋所费时间不多，工余饭后&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;杀上一盘&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;，开发智力，勤于动脑，调剂感情&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color:#333333;font-family:&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;,&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:宋体;font-size:16px;&quot;&gt;有利于开发智商居家必备。&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;br /&gt;', N'&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;1.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;准备&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;19&#215;19&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;棋盘两张&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;2.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;黑白子数目必须满足&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;3.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;第一回合先手只能下一手&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;,&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;其馀回合可以下连续两手&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;4.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;后手每回合均可以下连续两手&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;5.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;每颗子所投的棋盘没有限制&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;6.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;只要任意一方在两个棋盘上且同一个回合上连为五子为胜&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;7.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;若任意一方在两个棋盘上且不同一个回合上连为五子为负&lt;/span&gt;&lt;/p&gt;
&lt;p align=&quot;left&quot;&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;/p&gt;
&lt;div align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt;8.&lt;/span&gt;&lt;span style=&quot;color:#333333;line-height:150%;font-family:宋体;font-size:16px;&quot;&gt;若任意一方在不足两个棋盘上且同一个回合上连为五子为负&lt;/span&gt;&lt;span lang=&quot;EN-US&quot; style=&quot;color: rgb(51, 51, 51); line-height: 150%; font-size: 16px;&quot; arial&quot;,&quot;sans-serif&quot;;font-size:16px;&quot;=&quot;&quot;&gt; &lt;/span&gt;&lt;/div&gt;
&lt;div align=&quot;left&quot;&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;span style=&quot;font-size:16px;&quot;&gt; &lt;/span&gt;&lt;br /&gt;
&lt;/div&gt;', N'&amp;nbsp;&lt;br /&gt;', 0, 0, CAST(0x0000A6180148273B AS DateTime), CAST(0x0000A63200D0B9EF AS DateTime), 1036, 8)
INSERT [dbo].[GameRulesInfo] ([KindID], [KindName], [ThumbnailUrl], [ImgRuleUrl], [MobileGameType], [AndroidDownloadUrl], [IOSDownloadUrl], [HelpIntro], [HelpRule], [HelpGrade], [JoinIntro], [Nullity], [CollectDate], [ModifyDate], [PlayerNum], [GameScore]) VALUES (1002, N'通比牛牛', N'/Upload/Rules/2.png', N'/Upload/Rules/3.jpg', 0, N'', N'', N'&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;通比牛牛是一款地方性、游戏速度极快、刺激的棋牌游戏，主要流行在湖南、广东、广西地区。游戏可以由&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;人到&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;6&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;人同时进行，总共&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;54&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;张牌（含大小王，大小王可代替任何牌，由系统自行优化替换）。游戏开始后，系统将随机发给玩家每人&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;5&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;张牌，玩家将根据&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;5&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;张牌进行排列组合，组合出最大牌面的玩家将赢得本轮胜利，赢取其他玩家的对应数额金币。网络版通比牛牛在线玩&lt;/span&gt;&lt;/span&gt;', N'&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;【游戏用牌】&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;一副牌，总共&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;54&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;张牌（含大小王）&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;【术语说明】&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;1&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;有牛：任意三张牌点数能凑成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;30&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的整数，该牌便是有牛牌，剩余两张牌点数相加取个位数的值形成：牛&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;X&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;。&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;(&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;例如：&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&amp;nbsp;3&amp;nbsp;7&amp;nbsp;Q&amp;nbsp;5&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;，因为&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10+3+7=20&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;为&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;倍就已经有牛，&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;Q+5=15&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;，个位数为牛的点数，称之为牛&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;5)&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;2&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;牛牛：任意三张牌点数能凑成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;30&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的整数，剩余两张牌点数也能凑成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的整数，该牌型称为牛牛。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;3&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;无牛：任意三张牌都不能凑成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的倍数，该牌为无牛牌。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;4&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;百变：大小王可充当任意点数，称百变牌。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;5&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;底分：每个玩家游戏开始都要先下固定注，这里称为底分。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;6&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;．&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;摊牌：提示其他玩家自己的手牌已经排列组合完成，可以马上比牌。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;【牌型说明】&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;1.&amp;nbsp;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;牌型组合：&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;1)&amp;nbsp;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;牌局开始每个人手中都有五张牌，然后玩家需要将手中任意三张牌凑成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;点或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;20&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;点或&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;30&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;点都可以，这样是称之为牛。接下来再将其余的两张的点数相加得出几点，去掉十位数，只留个位数来进行比较，如果接下来两张的相加点数也正好是整数的话，那就是最大的牌型：&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;牛牛&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;2)&amp;nbsp;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;当玩家同时出现相同点数时，系统自动将两家手中牌最大那一张进行比较，谁大就由谁获得胜利。如果出现牌也相同大的情况，按照花色来进行比较，花色大小依次为黑桃、红桃、梅花、方块。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;2.&amp;nbsp;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;特殊牌型：&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;大王、小王、&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;K&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;、&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;Q&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;、&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;J&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;都是当&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;10&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;点，&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;A&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;当成&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;1&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;点，其他的牌型当自身的点数。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;3.&amp;nbsp;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;百变牌：&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
&lt;/span&gt;&lt;span style=&quot;color:#333333;font-family:Arial;font-size:14px;mso-spacerun:&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;大王和小王为百变牌型，可当任何牌。牛牛中，若&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;大小王&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;进行&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;百变&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;的话，那就属于&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;“&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;牛牛&lt;/span&gt;&lt;span style=&quot;font-family:Arial;font-size:14px;&quot;&gt;”&lt;/span&gt;&lt;span style=&quot;font-family:宋体;font-size:14px;&quot;&gt;中最小的牌型。&lt;/span&gt;&lt;/span&gt;&lt;span style=&quot;color: rgb(51, 51, 51); font-family: Arial; font-size: 14px;&quot; yes&quot;;mso-fareast-font-family:宋体;mso-font-kerning:0.0000pt;&quot;=&quot;&quot;&gt;&lt;br /&gt;
